sequence.script:
// Read raw payload string
var payloadString =
    mc.getVariable('data');


// Parse payload properly
var payload =
    JSON.parse(payloadString);

// Extract Base64 CSV
var base64Csv =
    payload["$"];

// Decode Base64
var Base64 =
    Packages.java.util.Base64;

var decodedBytes =
    Base64.getDecoder()
        .decode(base64Csv);

var csvContent =
    new java.lang.String(decodedBytes);

var timestamp = Date.now();

var lines =
    csvContent.trim().split("\n");

var headers =
    lines[0].split(",");

var transformedDrivers = [];

function toBoolean(val) {

    return String(val)
        .toLowerCase() === "true";
}

function toNumber(val) {

    return Number(val || 0);
}

for (var i = 1; i < lines.length; i++) {

    var values =
        lines[i].split(",");

    var row = {};

    for (var j = 0; j < headers.length; j++) {

        row[
            headers[j].trim()
        ] =
            values[j] != null
                ? values[j].trim()
                : null;
    }

    transformedDrivers.push({
        "partyType":
            row.partyType,
        "roleTypeCode":
            row.roleTypeCode
                ? [row.roleTypeCode]
                : [],

        "driverName":
            row.driverName,

        "driverDateOfBirth":
            row.driverDateOfBirth,

        "driverLicenseNumber":
            row.driverLicenseNumber,

        "driverLicenseJurisdictionCode":
            row.driverLicenseJurisdictionCode,

        "driverLicenseJurisdictionZipCode":
            row.driverLicenseJurisdictionZipCode,

        "drivingExperienceYearCount":
            toNumber(
                row.drivingExperienceYearCount
            ),

        "interstateDriverIndicator":
            toBoolean(
                row.interstateDriverIndicator
            ),

        "hazmatDriverEndorsementIndicator":
            toBoolean(
                row.hazmatDriverEndorsementIndicator
            ),

        "driverEmploymentClassificationCode":
            row.driverEmploymentClassificationCode,

        "driverMedicalCertificateNumber":
            row.driverMedicalCertificateNumber,

        "driverMedicalCertificateExpirationDate":
            row.driverMedicalCertificateExpirationDate,

        "cdlIndicator":
            toBoolean(
                row.cdlIndicator
            ),

        "cdlClassCode":
            row.cdlClassCode,

        "yearsLicensedCount":
            toNumber(
                row.yearsLicensedCount
            ),

        "accidentCount":
            toNumber(
                row.accidentCount
            ),

        "violationCount":
            toNumber(
                row.violationCount
            ),

        "status":
            row.status || "ACTIVE"

    });
}

mc.setPayloadJSON({
    "drivers":
        transformedDrivers
});
